let username: string = "张三";
let age: number = 25;
let isActive: boolean = true;
let items: string[] = ["苹果", "香蕉"];
let id: number | string = 1001;

// 函数类型注解
function greet(name: string): string {
  return `你好, ${name}`;
}

interface User {
  id: number;
  name: string;
  email: string;
  age?: number;
  readonly createdAt: Date;
}

const user: User = {
  id: 1,
  name: "张三",
  email: "zhangsan@mail.com",
  createdAt: new Date()
};

type ID = number | string;
type Point = { x: number; y: number };
type Callback = (data: string) => void;

const userId: ID = 1001;
const point: Point = { x: 10, y: 20 };
const handler: Callback = (data) => console.log(data);

// 联合类型
type Status = "pending" | "active" | "inactive";
let currentStatus: Status = "active";

// 可辨识联合
type SuccessResponse = { status: "success"; data: string };
type ErrorResponse = { status: "error"; message: string };
type ApiResponse = SuccessResponse | ErrorResponse;

function handleResponse(res: ApiResponse) {
  if (res.status === "success") {
    console.log(res.data); // TypeScript 知道此处是 SuccessResponse
  } else {
    console.log(res.message); // TypeScript 知道此处是 ErrorResponse
  }
}

enum Direction {
  Up = "UP",
  Down = "DOWN",
  Left = "LEFT",
  Right = "RIGHT"
}

let dir: Direction = Direction.Up;

// 数字枚举（自动递增）
enum HttpStatus {
  OK = 200,
  NotFound = 404,
  InternalError = 500
}

function identity<T>(value: T): T {
  return value;
}

const num = identity<number>(42);
const str = identity("hello"); // 类型推断，无需显式指定

// 实用示例：数组工具函数
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}

interface ApiResponse<T> {
  code: number;
  message: string;
  data: T;
}

interface User {
  id: number;
  name: string;
}

const userRes: ApiResponse<User> = {
  code: 200,
  message: "成功",
  data: { id: 1, name: "张三" }
};

const listRes: ApiResponse<User[]> = {
  code: 200,
  message: "成功",
  data: [{ id: 1, name: "张三" }]
};

interface HasLength {
  length: number;
}

function logLength<T extends HasLength>(value: T): void {
  console.log(value.length);
}

logLength("hello");    // 字符串有 length
logLength([1, 2, 3]); // 数组有 length
// logLength(123);    // 数字没有 length，编译报错

// keyof 约束
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

// 基本条件类型
type IsString<T> = T extends string ? "yes" : "no";
type A = IsString<string>;  // "yes"
type B = IsString<number>;  // "no"

// 实用示例：提取 Promise 内部类型
type UnwrapPromise<T> = T extends Promise<infer U> ? U : T;
type Result = UnwrapPromise<Promise<string>>; // string

// 内置工具类型
type ReadonlyUser = Readonly<User>;
type PartialUser = Partial<User>;
type RequiredUser = Required<User>;
type PickUser = Pick<User, "id" | "name">;
type OmitUser = Omit<User, "email">;
